class MyHashMap {
    constructor() {
        this.size = 1009;
        this.buckets = Array.from({ length: this.size }, () => []);
    }
    put(key, value) {
        const b = this.buckets[key % this.size];
        for (const pair of b) {
            if (pair[0] === key) { pair[1] = value; return; }
        }
        b.push([key, value]);
    }
    get(key) {
        const b = this.buckets[key % this.size];
        for (const pair of b) {
            if (pair[0] === key) return pair[1];
        }
        return -1;
    }
    remove(key) {
        const b = this.buckets[key % this.size];
        for (let i = 0; i < b.length; i++) {
            if (b[i][0] === key) { b.splice(i, 1); return; }
        }
    }
}
